-- Målrettet seed: KUN de 5 nye Norge–England-quizene (num 20–24).
-- Trygt å kjøre alene i Supabase → SQL Editor. Rører ikke de 18 eksisterende radene.
-- Alle 5 settes status='open' (publisert).

insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'norge-england-historie', '20', 'Historie',
  'Norge–England gjennom historien', '«Maggie Thatcher, your boys took a hell of a beating!» To Oslo-sjokk — og aldri før i et VM.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Kuriosa", "q": "Hva gjør kvartfinalen 11. juli historisk for Norge og England?", "options": ["Det er første kamp mellom dem på 40 år", "Det er første gang de møtes i et VM-sluttspill", "Det er første gang begge er i en kvartfinale", "Det er første VM-kamp i Miami"], "correct": 1, "explanation": "Landene har møtt hverandre 11 ganger før, men aldri i et VM-sluttspill — kvartfinalen i Miami er det aller første VM-møtet."}, {"category": "Historie", "q": "Norge har bare slått England to ganger gjennom historien. I hvilken by kom begge seirene?", "options": ["Oslo", "Bergen", "Manchester", "London"], "correct": 0, "explanation": "Begge de norske seirene — 1981 og 1993 — kom på Ullevaal i Oslo."}, {"category": "Legende", "q": "Norges 2–1-seier i 1981 ga en av tidenes mest berømte radioreportasjer. Hva ropte Bjørge Lillelien?", "options": ["«Maggie Thatcher, your boys took a hell of a beating!»", "«England, England, farvel og takk!»", "«Dette er større enn Grotli!»", "«Norge er best i verden!»"], "correct": 0, "explanation": "Lillelien ramset opp britiske størrelser og avsluttet med «Maggie Thatcher, your boys took a hell of a beating!» — en av fotballhistoriens mest siterte reportasjer."}, {"category": "Historie", "q": "Hva ble resultatet i den berømte kampen i Oslo i 1981?", "options": ["3–2 til Norge", "2–1 til Norge", "2–2", "1–0 til Norge"], "correct": 1, "explanation": "Norge vant 2–1 i en VM-kvalifiseringskamp. Bryan Robson ga England ledelsen før Albertsen og Thoresen snudde det."}, {"category": "Stjerner", "q": "Hvem scoret Norges vinnermål i 2–1-seieren over England i 1981?", "options": ["Roger Albertsen", "Kjetil Rekdal", "Tore André Flo", "Hallvar Thoresen"], "correct": 3, "explanation": "Roger Albertsen utlignet, og Hallvar Thoresen satte vinnermålet i det 41. minutt."}, {"category": "Historie", "q": "Hva ble resultatet da Norge slo England igjen i Oslo i 1993?", "options": ["2–0 til Norge", "1–0 til Norge", "2–1 til Norge", "3–1 til Norge"], "correct": 0, "explanation": "Øyvind Leonhardsen og Lars Bohinen scoret i en 2–0-seier i VM-kvalifiseringen."}, {"category": "Drama", "q": "Hva ble konsekvensen for England av å tape 0–2 i Oslo i 1993?", "options": ["Ingenting, begge gikk videre", "England ble utestengt fra neste VM", "England kom ikke til VM 1994 — Norge gjorde det", "England fikk en ny sjanse i omspill"], "correct": 2, "explanation": "Norge vant gruppa foran Nederland og England. England endte utenfor og misset VM 1994 i USA."}, {"category": "Kuriosa", "q": "I en vennskapskamp i Oslo i 1966 vant England 6–1, med én spiller som scoret fire mål. Hvem?", "options": ["Gary Lineker", "Geoff Hurst", "Jimmy Greaves", "Bobby Charlton"], "correct": 2, "explanation": "Jimmy Greaves scoret fire i 6–1-seieren — samme år England vant sitt eneste VM."}, {"category": "Rekord", "q": "Hvordan så den innbyrdes statistikken ut før VM 2026 — hvem hadde flest seire?", "options": ["Helt likt, tre seire hver", "Norge, med flest seire", "De hadde aldri møttes", "England, med seks seire mot Norges to"], "correct": 3, "explanation": "Før kvartfinalen: England seks seire, tre uavgjort, Norge to seire på elleve møter."}, {"category": "Resonnement", "q": "Norges to seire mot England har én ting til felles utover byen (Oslo). Hva?", "options": ["Begge ble spilt på nøytral bane", "Begge kom i EM-kvalifisering", "Begge var vennskapskamper", "Begge var VM-kvalifiseringskamper"], "correct": 3, "explanation": "Både 1981 (mot VM 1982) og 1993 (mot VM 1994) var VM-kvalifiseringskamper — passende nok før det første VM-møtet i 2026."}]'::jsonb, 'open', 20, true
)
