insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'england-stjerner', '21', 'Motstander',
  'Motstanderen: Englands stjerner', 'Kane, Bellingham, en tysk sjef og to vrakede stjerner — hvem møter Norge i Miami?', 'vm-gruppespill-1', 'middels',
  '[{"category": "Kaptein", "q": "Hvem er Englands kaptein og spissas i VM 2026?", "options": ["Harry Kane", "Jude Bellingham", "Bukayo Saka", "Declan Rice"], "correct": 0, "explanation": "Harry Kane fører an og bærer kapteinsbindet for England."}, {"category": "Rekord", "q": "Kane har passert hvilken legende som Englands mestscorende i VM-sluttspill?", "options": ["Gary Lineker", "Michael Owen", "Alan Shearer", "Bobby Charlton"], "correct": 0, "explanation": "Kane gikk forbi Gary Lineker som Englands mestscorende gjennom tidene i VM-sluttspill."}, {"category": "Klubb", "q": "Hvilken klubb spiller Harry Kane for i 2026?", "options": ["Manchester United", "Real Madrid", "Tottenham", "Bayern München"], "correct": 3, "explanation": "Kane forlot Tottenham for Bayern München i 2023 og spiller fortsatt der."}, {"category": "Stjerner", "q": "Jude Bellingham scoret to mål da England slo en vertsnasjon 3–2 i åttedelsfinalen. Hvilken?", "options": ["Mexico", "USA", "Brasil", "Canada"], "correct": 0, "explanation": "Bellingham herjet da England vant 3–2 mot Mexico på Azteca i Mexico by."}, {"category": "Resonnement", "q": "To av Englands startspillere er klubbkamerater med Norges kaptein Ødegaard. I hvilken klubb?", "options": ["Real Madrid", "Chelsea", "Arsenal", "Manchester City"], "correct": 2, "explanation": "Bukayo Saka og Declan Rice spiller for Arsenal — samme klubb som Ødegaard er kaptein for."}, {"category": "Trener", "q": "Hva er spesielt med Englands landslagssjef i VM 2026?", "options": ["Han spilte selv i VM 1998", "Han er tidligere Norge-spiller", "Han er tysk — Thomas Tuchel", "Han er svensk"], "correct": 2, "explanation": "Thomas Tuchel, tysk og Champions League-vinner med Chelsea i 2021, tok over som England-sjef 1. januar 2025."}, {"category": "Kuriosa", "q": "Hvilke to store offensive navn valgte Tuchel kontroversielt å ikke ta med i VM-troppen?", "options": ["Phil Foden og Cole Palmer", "Declan Rice og Harry Kane", "Bukayo Saka og Jude Bellingham", "Marcus Rashford og Jack Grealish"], "correct": 0, "explanation": "Tuchel vraket både Phil Foden og Cole Palmer etter svakere klubbsesonger — en av mesterskapets store snakkiser."}, {"category": "Keeper", "q": "Hvem er Englands førstekeeper i VM 2026?", "options": ["Nick Pope", "Jordan Pickford", "Dean Henderson", "Aaron Ramsdale"], "correct": 1, "explanation": "Jordan Pickford har stått i alle kampene og er Englands ubestridte førstevalg i mål."}, {"category": "Sluttspill", "q": "England kom til kvartfinalen etter en snuoperasjon i 16-delsfinalen. Hvem slo de i R32 (2–1)?", "options": ["DR Kongo", "Ecuador", "Senegal", "Nigeria"], "correct": 0, "explanation": "England lå under, men snudde til 2–1 mot DR Kongo i 32-delsfinalen — Kane avgjorde sent."}, {"category": "Drama", "q": "Hva gjorde slutten på Englands 3–2-seier over Mexico ekstra dramatisk?", "options": ["Kampen gikk til straffesparkkonkurranse", "England spilte de siste minuttene med ti mann etter rødt kort", "Mexico brente straffe på overtid", "Kane ble båret av skadet"], "correct": 1, "explanation": "Jarell Quansah fikk rødt kort, Mexico reduserte på straffe, men England holdt ut 3–2 med ti mann."}]'::jsonb, 'open', 21, true
)
