insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'pregame-norge-england', '22', 'Pre-game',
  'Før kampen: Norge–England', 'Norges første VM-kvartfinale noensinne. Haaland mot Kane i Miami — ta den før avspark.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Sluttspill", "q": "Når og hvor møtes Norge og England i kvartfinalen?", "options": ["11. juli på Azteca", "10. juli i Dallas", "11. juli på Hard Rock Stadium i Miami", "12. juli i New York"], "correct": 2, "explanation": "Kvartfinalen spilles lørdag 11. juli på Hard Rock Stadium i Miami, avspark 23:00 norsk tid."}, {"category": "Norge", "q": "Hvordan tok Norge seg til kvartfinalen?", "options": ["Ved å vinne gruppe I", "Ved å slå England i gruppespillet", "Ved å slå Brasil 2–1 i åttedelsfinalen", "På straffer mot Brasil"], "correct": 2, "explanation": "Norge slo den femdobbelte verdensmesteren Brasil 2–1 (1–2 borte) i åttedelsfinalen 5. juli."}, {"category": "Stjerner", "q": "Hvem scoret begge Norges mål i 2–1-seieren over Brasil?", "options": ["Erling Haaland", "Antonio Nusa", "Alexander Sørloth", "Martin Ødegaard"], "correct": 0, "explanation": "Haaland scoret begge — i det 79. og 90. minutt — og sendte Norge til deres første VM-kvartfinale."}, {"category": "Historisk", "q": "Hvorfor er kvartfinalen historisk for de to nasjonene?", "options": ["Det er første gang Norge og England møtes i et VM-sluttspill", "Det er første kamp i Miami", "Det er finalen", "Det er første gang begge er i VM"], "correct": 0, "explanation": "De har aldri før møtt hverandre i et VM-sluttspill — kvartfinalen er det aller første VM-møtet."}, {"category": "England", "q": "England kom til kvartfinalen etter en thriller mot en vertsnasjon i R16. Hva ble resultatet?", "options": ["2–1 over USA", "3–2 over Mexico", "1–0 over Mexico", "4–3 over Canada"], "correct": 1, "explanation": "England vant 3–2 mot Mexico på Azteca, og holdt ut med ti mann på tampen."}, {"category": "Kapteiner", "q": "Hvem fører an som kapteiner for de to lagene?", "options": ["Ødegaard for Norge, Kane for England", "Haaland for Norge, Bellingham for England", "Sørloth for Norge, Saka for England", "Berge for Norge, Rice for England"], "correct": 0, "explanation": "Martin Ødegaard er Norges kaptein, Harry Kane Englands."}, {"category": "Haaland", "q": "Hvor mange mål har Erling Haaland scoret så langt i VM 2026?", "options": ["Ti", "Fem", "Sju", "Fire"], "correct": 2, "explanation": "Haaland står med sju mål: fire i gruppespillet, vinnermålet mot Elfenbenskysten og begge mot Brasil."}, {"category": "Innsats", "q": "Hva står på spill i kvartfinalen — hvor går vinneren?", "options": ["Rett til finalen", "Til bronsefinalen", "Tilbake til gruppespill", "Til semifinalen"], "correct": 3, "explanation": "Vinneren av kvartfinalen går videre til VM-semifinalen."}, {"category": "Milepæl", "q": "Hvorfor er Norges sluttspill i 2026 historisk?", "options": ["Norge er regjerende verdensmester", "Det er Norges første VM-kvartfinale noensinne", "Det er Norges femte strake VM", "Norge har aldri vært i VM før"], "correct": 1, "explanation": "Norge er i sin første VM-kvartfinale noensinne — og spiller sitt første VM på 28 år."}, {"category": "Resonnement", "q": "England jakter tittelen de bare har vunnet én gang. Når vant England VM?", "options": ["Aldri", "1990", "1966", "2018"], "correct": 2, "explanation": "England vant VM én gang, på hjemmebane i 1966 — og har jaktet nummer to siden."}]'::jsonb, 'open', 22, true
)
