insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'stjerne-haaland', '23', 'Stjerneportrett',
  'Stjerneportrett: Erling Haaland', 'Målmaskinen som senket Brasil — og som faktisk ble født i England. Hvor godt kjenner du ham?', 'vm-gruppespill-1', 'middels',
  '[{"category": "Klubb", "q": "Hvilken klubb spiller Erling Haaland for?", "options": ["Manchester United", "Manchester City", "Real Madrid", "Borussia Dortmund"], "correct": 1, "explanation": "Haaland gikk til Manchester City i 2022 og vant «the treble» i sin første sesong."}, {"category": "Rekord", "q": "Haaland er Norges tidenes toppscorer. Hvilken rekord fra for ~90 år siden slo han?", "options": ["Tore André Flos rekord", "Ole Gunnar Solskjærs rekord", "Jørgen Juves 33 landslagsmål", "Kjetil Rekdals målrekord"], "correct": 2, "explanation": "Haaland passerte Jørgen Juves 33 mål — en rekord som hadde stått i rundt 90 år."}, {"category": "Premier League", "q": "Hvor mange mål scoret Haaland i sin første Premier League-sesong — en ny rekord?", "options": ["41", "30", "25", "36"], "correct": 3, "explanation": "36 mål i 2022–23 er rekord for flest mål i en 38-kampers Premier League-sesong."}, {"category": "Ungdom", "q": "Hvilke to norske klubber spilte Haaland for før han dro utenlands?", "options": ["Vålerenga og Lillestrøm", "Bryne og Molde", "Start og Viking", "Rosenborg og Brann"], "correct": 1, "explanation": "Haaland startet i Bryne og fikk gjennombruddet i Molde før overgangen til Salzburg."}, {"category": "Karriere", "q": "Ved hvilken tysk klubb fikk Haaland sitt store europeiske gjennombrudd før City?", "options": ["Bayern München", "RB Leipzig", "Borussia Dortmund", "Schalke 04"], "correct": 2, "explanation": "Haaland herjet for Borussia Dortmund (2020–22) og vant DFB-Pokal i 2021."}, {"category": "VM-kvalik", "q": "Haaland satte europarekord i VM-kvalifiseringen til 2026. Hvor mange mål scoret han?", "options": ["20 mål", "10 mål", "16 mål på 8 kamper", "12 mål"], "correct": 2, "explanation": "16 mål på 8 kamper — han scoret i hver eneste kvalifiseringskamp, en europeisk rekord han deler med Lewandowski."}, {"category": "Fakta", "q": "Haaland er født i 2000. Hvor gammel er han under VM 2026?", "options": ["25", "23", "21", "28"], "correct": 0, "explanation": "Født 21. juli 2000 — Haaland er 25 år gjennom hele sluttspillet og fyller 26 den 21. juli, etter VM-finalen."}, {"category": "Familie", "q": "Haalands far var også proffspiller i Premier League. Hva heter han?", "options": ["Kjetil Rekdal", "Ole Gunnar Solskjær", "Jostein Flo", "Alf-Inge Håland"], "correct": 3, "explanation": "Alf-Inge Håland spilte for blant andre Leeds United og Manchester City."}, {"category": "Kuriosa", "q": "I hvilket land ble Erling Haaland faktisk født — passende nok før kvartfinalen?", "options": ["Spania", "Norge", "Tyskland", "England"], "correct": 3, "explanation": "Haaland ble født i Leeds i England mens faren spilte for Leeds United — han vokste opp som Leeds-supporter."}, {"category": "VM 2026", "q": "Haalands to sene mål slo ut hvilken femdobbelt verdensmester i åttedelsfinalen?", "options": ["Argentina", "Italia", "Tyskland", "Brasil"], "correct": 3, "explanation": "Haaland scoret begge målene da Norge slo Brasil 2–1 i åttedelsfinalen 5. juli."}]'::jsonb, 'open', 23, true
)
