insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'stjerne-odegaard', '24', 'Stjerneportrett',
  'Stjerneportrett: Martin Ødegaard', 'Vidunderbarnet som ble kaptein i to land. Dirigenten Norge bygger spillet rundt.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Klubb", "q": "Hvilken klubb er Martin Ødegaard kaptein for?", "options": ["Real Madrid", "Manchester City", "Arsenal", "Real Sociedad"], "correct": 2, "explanation": "Ødegaard ble utnevnt til Arsenal-kaptein i 2022 og er også kaptein for Norge."}, {"category": "Rekord", "q": "Ødegaard er Norges yngste landslagsspiller noensinne. Hvor gammel var han da han debuterte?", "options": ["18 år", "19 år", "17 år", "15 år"], "correct": 3, "explanation": "Han debuterte for Norge i 2014, 15 år og 253 dager gammel — fortsatt Norges yngste landslagsspiller."}, {"category": "Karriere", "q": "Som tenåring signerte Ødegaard for en av verdens største klubber. Hvilken?", "options": ["Juventus", "Bayern München", "Barcelona", "Real Madrid"], "correct": 3, "explanation": "Real Madrid hentet ham som 16-åring i 2015 — han ble klubbens yngste spiller på det tidspunktet."}, {"category": "Ungdom", "q": "Ved hvilken norsk klubb fikk Ødegaard gjennombruddet sitt?", "options": ["Vålerenga", "Rosenborg", "Molde", "Strømsgodset"], "correct": 3, "explanation": "Ødegaard slo gjennom i Strømsgodset som 15-åring og satte rekord som yngste målscorer i eliteserien."}, {"category": "Posisjon", "q": "Hvilken posisjon spiller Ødegaard?", "options": ["Midtstopper", "Offensiv midtbane (playmaker)", "Spiss", "Keeper"], "correct": 1, "explanation": "Ødegaard er en kreativ, offensiv midtbanespiller — dirigenten som styrer angrepsspillet."}, {"category": "Landslag", "q": "Siden hvilket år har Ødegaard vært kaptein for Norge?", "options": ["2021", "2018", "2016", "2023"], "correct": 0, "explanation": "Ødegaard har vært Norges kaptein siden mars 2021."}, {"category": "Karriere", "q": "Før han slo rot i Arsenal, var Ødegaard på lån i Spania. Hvilken spansk klubb?", "options": ["Sevilla", "Real Sociedad", "Valencia", "Real Betis"], "correct": 1, "explanation": "Ødegaard var på lån i Real Sociedad før den permanente overgangen til Arsenal i 2021."}, {"category": "VM-rolle", "q": "Hvilken rolle har Ødegaard for Norge i VM 2026?", "options": ["Høyreback", "Trener", "Kaptein", "Reservekeeper"], "correct": 2, "explanation": "Ødegaard er kaptein og Norges dirigent på midtbanen."}, {"category": "Arsenal", "q": "I hvilket år ble Ødegaard utnevnt til kaptein i Arsenal?", "options": ["2020", "2022", "2021", "2023"], "correct": 1, "explanation": "Ødegaard fikk kapteinsbindet i Arsenal i 2022, året etter den permanente overgangen."}, {"category": "Resonnement", "q": "Ødegaard møter to av sine egne Arsenal-lagkamerater på Englands lag. Hvem spiller de for til daglig?", "options": ["Bayern — Kane", "Arsenal — Saka og Rice", "Real Madrid — Bellingham", "Manchester City — Haaland"], "correct": 1, "explanation": "Bukayo Saka og Declan Rice er Ødegaards klubbkamerater i Arsenal, men motstandere i kvartfinalen."}]'::jsonb, 'open', 24, true
)
